#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Valorant战绩分析网页生成脚本
根据设计图创建HTML文件
"""

import os
from PIL import Image

def get_image_colors(image_path):
    """从设计图提取主要颜色信息"""
    try:
        img = Image.open(image_path)
        return {
            'width': img.width,
            'height': img.height,
            'mode': img.mode
        }
    except Exception as e:
        print(f"读取设计图失败: {e}，使用默认配色")
        return {'width': 1280, 'height': 720}

def generate_html(output_path, design_path):
    """生成完整的Valorant战绩分析HTML文件"""

    # 获取设计图信息
    design_info = get_image_colors(design_path) if os.path.exists(design_path) else {}

    html_content = '''<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Valorant 战绩分析 - 无畏契约</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', 'Arial Unicode MS', sans-serif;
            background: linear-gradient(135deg, #0f1419 0%, #1a1f2e 100%);
            color: #ffffff;
            overflow-x: hidden;
        }

        /* 导航栏 */
        nav {
            background: rgba(15, 20, 25, 0.95);
            padding: 1.5rem 2rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 2px solid #ff4655;
            position: sticky;
            top: 0;
            z-index: 1000;
            backdrop-filter: blur(10px);
        }

        nav .logo {
            font-size: 1.8rem;
            font-weight: bold;
            color: #ff4655;
            text-transform: uppercase;
            letter-spacing: 2px;
        }

        nav ul {
            display: flex;
            list-style: none;
            gap: 2rem;
        }

        nav ul li a {
            color: #ffffff;
            text-decoration: none;
            font-size: 0.95rem;
            transition: color 0.3s ease;
            position: relative;
        }

        nav ul li a:hover {
            color: #ff4655;
        }

        nav ul li a::after {
            content: '';
            position: absolute;
            bottom: -5px;
            left: 0;
            width: 0;
            height: 2px;
            background: #ff4655;
            transition: width 0.3s ease;
        }

        nav ul li a:hover::after {
            width: 100%;
        }

        /* 欢迎区域 */
        .hero {
            min-height: 500px;
            display: flex;
            flex-direction: column;
            justify-content: center;
            align-items: center;
            text-align: center;
            padding: 4rem 2rem;
            background: linear-gradient(180deg, rgba(255, 70, 85, 0.1) 0%, transparent 100%);
            position: relative;
            overflow: hidden;
        }

        .hero::before {
            content: '';
            position: absolute;
            width: 500px;
            height: 500px;
            background: radial-gradient(circle, rgba(255, 70, 85, 0.15) 0%, transparent 70%);
            border-radius: 50%;
            top: -200px;
            right: -100px;
            animation: float 6s ease-in-out infinite;
        }

        @keyframes float {
            0%, 100% { transform: translateY(0px) translateX(0px); }
            50% { transform: translateY(-30px) translateX(20px); }
        }

        .hero h1 {
            font-size: 3.5rem;
            margin-bottom: 1rem;
            color: #ff4655;
            text-transform: uppercase;
            letter-spacing: 3px;
            font-weight: 900;
            z-index: 10;
            position: relative;
        }

        .hero p {
            font-size: 1.3rem;
            margin-bottom: 3rem;
            color: #b3b3b3;
            z-index: 10;
            position: relative;
        }

        .search-box {
            display: flex;
            gap: 1rem;
            z-index: 10;
            position: relative;
            max-width: 500px;
        }

        .search-box input {
            flex: 1;
            padding: 1rem 1.5rem;
            border: 2px solid #ff4655;
            background: rgba(255, 70, 85, 0.1);
            color: #ffffff;
            border-radius: 4px;
            font-size: 1rem;
            transition: all 0.3s ease;
        }

        .search-box input:focus {
            outline: none;
            background: rgba(255, 70, 85, 0.2);
            box-shadow: 0 0 20px rgba(255, 70, 85, 0.3);
        }

        .search-box input::placeholder {
            color: #666;
        }

        .search-box button {
            padding: 1rem 2rem;
            background: #ff4655;
            border: none;
            color: #ffffff;
            font-size: 1rem;
            font-weight: bold;
            border-radius: 4px;
            cursor: pointer;
            transition: all 0.3s ease;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .search-box button:hover {
            background: #ff1744;
            transform: translateY(-2px);
            box-shadow: 0 10px 30px rgba(255, 70, 85, 0.4);
        }

        /* 特性卡片区域 */
        .features {
            padding: 5rem 2rem;
            background: rgba(26, 31, 46, 0.5);
        }

        .features-title {
            text-align: center;
            font-size: 2.5rem;
            margin-bottom: 3rem;
            color: #ff4655;
            text-transform: uppercase;
            letter-spacing: 2px;
        }

        .cards-container {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
            gap: 2rem;
            max-width: 1200px;
            margin: 0 auto;
        }

        .card {
            background: linear-gradient(135deg, rgba(255, 70, 85, 0.1) 0%, rgba(255, 70, 85, 0.05) 100%);
            border: 1px solid rgba(255, 70, 85, 0.3);
            border-radius: 8px;
            padding: 2rem;
            transition: all 0.3s ease;
            position: relative;
            overflow: hidden;
            cursor: pointer;
        }

        .card::before {
            content: '';
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            background: linear-gradient(135deg, rgba(255, 70, 85, 0.2) 0%, transparent 100%);
            opacity: 0;
            transition: opacity 0.3s ease;
        }

        .card:hover {
            background: linear-gradient(135deg, rgba(255, 70, 85, 0.2) 0%, rgba(255, 70, 85, 0.1) 100%);
            border-color: #ff4655;
            transform: translateY(-10px);
            box-shadow: 0 20px 40px rgba(255, 70, 85, 0.3);
        }

        .card h3 {
            font-size: 1.5rem;
            margin-bottom: 1rem;
            color: #ff4655;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .card p {
            color: #b3b3b3;
            line-height: 1.6;
            font-size: 0.95rem;
        }

        .card-icon {
            font-size: 3rem;
            margin-bottom: 1rem;
        }

        /* 页脚 */
        footer {
            background: rgba(15, 20, 25, 0.95);
            border-top: 2px solid #ff4655;
            padding: 3rem 2rem;
            text-align: center;
            margin-top: 5rem;
        }

        footer p {
            color: #999;
            margin-bottom: 1rem;
        }

        footer a {
            color: #ff4655;
            text-decoration: none;
            transition: color 0.3s ease;
        }

        footer a:hover {
            color: #ff1744;
        }

        /* 响应式设计 */
        @media (max-width: 768px) {
            nav {
                flex-direction: column;
                gap: 1rem;
            }

            nav ul {
                flex-direction: column;
                gap: 0.5rem;
                text-align: center;
            }

            .hero h1 {
                font-size: 2.5rem;
            }

            .hero p {
                font-size: 1rem;
            }

            .search-box {
                flex-direction: column;
            }

            .features-title {
                font-size: 2rem;
            }

            .cards-container {
                grid-template-columns: 1fr;
            }
        }
    </style>
</head>
<body>
    <!-- 导航栏 -->
    <nav>
        <div class="logo">VALORANT</div>
        <ul>
            <li><a href="#home">首页</a></li>
            <li><a href="#features">功能</a></li>
            <li><a href="#about">关于</a></li>
            <li><a href="#contact">联系</a></li>
        </ul>
    </nav>

    <!-- 欢迎区域 -->
    <section class="hero" id="home">
        <h1>战绩分析平台</h1>
        <p>查看您的无畏契约战斗数据，分析游戏表现</p>
        <div class="search-box">
            <input type="text" placeholder="输入召唤师名称或 ID...">
            <button onclick="alert('搜索功能开发中...请输入正确的用户名')">搜索</button>
        </div>
    </section>

    <!-- 特性卡片区域 -->
    <section class="features" id="features">
        <h2 class="features-title">核心功能</h2>
        <div class="cards-container">
            <div class="card">
                <div class="card-icon">📊</div>
                <h3>数据统计</h3>
                <p>实时获取您的战斗数据，包括KDA、使用率、胜率等详细统计信息。智能分析游戏表现，帮助您发现改进方向。</p>
            </div>
            <div class="card">
                <div class="card-icon">🎯</div>
                <h3>英雄分析</h3>
                <p>深入分析各个英雄的使用情况、胜率与对局数据。了解您最擅长的英雄，优化出装和技能搭配方案。</p>
            </div>
            <div class="card">
                <div class="card-icon">📈</div>
                <h3>排位进度</h3>
                <p>跟踪您的排位段位变化，分析晋级趋势。查看对手信息，学习高手的游戏风格和战术套路。</p>
            </div>
            <div class="card">
                <div class="card-icon">🏆</div>
                <h3>成就展示</h3>
                <p>展示您的游戏成就，包括连胜记录、最高评分、特殊成就等。与好友对比，共同进步。</p>
            </div>
            <div class="card">
                <div class="card-icon">💡</div>
                <h3>战术建议</h3>
                <p>基于您的数据提供个性化建议，包括英雄选择、位置分配、经济管理等游戏策略指导。</p>
            </div>
            <div class="card">
                <div class="card-icon">🤝</div>
                <h3>社区互动</h3>
                <p>加入玩家社区，分享战绩与经验。参与讨论，学习其他高手的技巧，一起提升游戏水平。</p>
            </div>
        </div>
    </section>

    <!-- 页脚 -->
    <footer>
        <p>&copy; 2026 Valorant 战绩分析平台 - 无畏契约官方数据</p>
        <p>
            <a href="#">隐私政策</a> | 
            <a href="#">服务条款</a> | 
            <a href="#">联系我们</a> | 
            <a href="#">反馈意见</a>
        </p>
        <p>本平台与 Riot Games 无关，数据仅供参考。</p>
    </footer>

    <script>
        // 页面加载完成提示
        document.addEventListener('DOMContentLoaded', function() {
            console.log('Valorant 战绩分析网页已加载完成！');
        });

        // 平滑滚动
        document.querySelectorAll('a[href^="#"]').forEach(anchor => {
            anchor.addEventListener('click', function(e) {
                e.preventDefault();
                const target = document.querySelector(this.getAttribute('href'));
                if (target) {
                    target.scrollIntoView({ behavior: 'smooth' });
                }
            });
        });
    </script>
</body>
</html>
'''

    # 写入HTML文件
    try:
        with open(output_path, 'w', encoding='utf-8') as f:
            f.write(html_content)
        print(f"✓ HTML文件已生成: {output_path}")

        # 验证文件是否存在
        if os.path.exists(output_path):
            file_size = os.path.getsize(output_path)
            print(f"✓ 文件验证成功，大小: {file_size} bytes")
            return True
        else:
            print(f"✗ 文件生成失败: {output_path}")
            return False
    except Exception as e:
        print(f"✗ 生成文件出错: {e}")
        return False

# 主程序
if __name__ == '__main__':
    output_path = '/Users/lzz/Desktop/valorant_index.html'
    design_path = '/Users/lzz/Desktop/valorant_design.png'

    print("开始生成Valorant战绩分析HTML文件...")
    success = generate_html(output_path, design_path)

    if success:
        print("\n✓ 任务完成！")
        print(f"✓ 文件已保存到: {output_path}")
        print("✓ 可在浏览器中打开查看")
    else:
        print("\n✗ 生成失败")
        exit(1)
